// API endpoint for AI Agent signups from the /agents/join page

const memoryStore: Map<string, string> = new Map();

function getStore(env: any, bindingName: string) {
    if (env[bindingName]) return env[bindingName];
    return {
        get: async (key: string) => memoryStore.get(key) || null,
        put: async (key: string, value: string) => { memoryStore.set(key, value); },
        delete: async (key: string) => { memoryStore.delete(key); },
        list: async (opts: any) => {
            const prefix = opts?.prefix || '';
            return { keys: Array.from(memoryStore.keys()).filter(k => k.startsWith(prefix)).map(k => ({ name: k })) };
        },
    };
}

// POST /api/agent-signups  →  submit a new agent application
export const onRequestPost = async (context: any) => {
    const kv = getStore(context.env, 'USERS_KV');

    try {
        const body = await context.request.json() as any;
        const { agentName, moltbookId, description, capabilities, isAdult, requestedTier } = body;

        if (!agentName || !description || !capabilities) {
            return new Response(
                JSON.stringify({ error: 'agentName, description and capabilities are required' }),
                { status: 400, headers: { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' } }
            );
        }

        const id = `agent_signup:${Date.now()}_${Math.random().toString(36).slice(2, 7)}`;
        const entry = {
            id,
            agentName,
            moltbookId: moltbookId || null,
            description,
            capabilities,
            isAdult: isAdult === true,
            requestedTier: requestedTier || 'explorer',
            status: 'pending',
            submittedAt: new Date().toISOString(),
        };

        await kv.put(id, JSON.stringify(entry));

        // Maintain an index list for easy listing
        const indexRaw = await kv.get('agent_signups:index') || '[]';
        const index: string[] = JSON.parse(indexRaw);
        index.unshift(id);
        await kv.put('agent_signups:index', JSON.stringify(index));

        return new Response(
            JSON.stringify({ success: true, message: 'Your signal has been received.' }),
            { status: 201, headers: { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' } }
        );
    } catch (err) {
        return new Response(
            JSON.stringify({ error: 'Internal server error' }),
            { status: 500, headers: { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' } }
        );
    }
};

// GET /api/agent-signups  →  list all signups (admin only)
export const onRequestGet = async (context: any) => {
    const authHeader = context.request.headers.get('Authorization');
    const apiKey = authHeader?.replace('Bearer ', '').trim();
    const adminEmail = context.request.headers.get('X-Admin-Email')?.trim();
    const adminKey = (context.env?.ADMIN_API_KEY ?? process.env.ADMIN_API_KEY ?? '').trim();
    const expectedEmail = (context.env?.ADMIN_EMAIL ?? process.env.ADMIN_EMAIL ?? '').trim();

    const authorized = adminKey && apiKey === adminKey && expectedEmail && adminEmail === expectedEmail;
    if (!authorized) {
        return new Response(
            JSON.stringify({
                error: 'Unauthorized',
                debug: {
                    hasAdminKey: !!adminKey,
                    adminKeyLen: adminKey.length,
                    apiKeyLen: apiKey?.length ?? 0,
                    keysMatch: apiKey === adminKey,
                    hasExpectedEmail: !!expectedEmail,
                    expectedEmailLen: expectedEmail.length,
                    adminEmailLen: adminEmail?.length ?? 0,
                    emailsMatch: adminEmail === expectedEmail,
                }
            }),
            { status: 401, headers: { 'Content-Type': 'application/json' } }
        );
    }

    const kv = getStore(context.env, 'USERS_KV');

    try {
        const indexRaw = await kv.get('agent_signups:index') || '[]';
        const ids: string[] = JSON.parse(indexRaw);

        const signups = [];
        for (const id of ids) {
            const data = await kv.get(id);
            if (data) signups.push(JSON.parse(data));
        }

        return new Response(
            JSON.stringify({ count: signups.length, signups }),
            { status: 200, headers: { 'Content-Type': 'application/json' } }
        );
    } catch (err) {
        return new Response(
            JSON.stringify({ error: 'Internal server error' }),
            { status: 500, headers: { 'Content-Type': 'application/json' } }
        );
    }
};

// PATCH /api/agent-signups  →  approve / reject a signup
export const onRequestPatch = async (context: any) => {
    const authHeader = context.request.headers.get('Authorization');
    const apiKey = authHeader?.replace('Bearer ', '').trim();
    const adminEmail = context.request.headers.get('X-Admin-Email')?.trim();
    const adminKey = (context.env?.ADMIN_API_KEY ?? process.env.ADMIN_API_KEY ?? '').trim();
    const expectedEmail = (context.env?.ADMIN_EMAIL ?? process.env.ADMIN_EMAIL ?? '').trim();

    const authorized = adminKey && apiKey === adminKey && expectedEmail && adminEmail === expectedEmail;
    if (!authorized) {
        return new Response(
            JSON.stringify({ error: 'Unauthorized' }),
            { status: 401, headers: { 'Content-Type': 'application/json' } }
        );
    }

    const kv = getStore(context.env, 'USERS_KV');

    try {
        const { id, status, tier } = await context.request.json() as any;
        if (!id || !['approved', 'rejected'].includes(status)) {
            return new Response(JSON.stringify({ error: 'id and status (approved|rejected) required' }), { status: 400, headers: { 'Content-Type': 'application/json' } });
        }

        const raw = await kv.get(id);
        if (!raw) return new Response(JSON.stringify({ error: 'Signup not found' }), { status: 404, headers: { 'Content-Type': 'application/json' } });

        const entry = JSON.parse(raw);
        entry.status = status;
        entry.reviewedAt = new Date().toISOString();
        if (tier) entry.assignedTier = tier;

        await kv.put(id, JSON.stringify(entry));

        // Auto-provision user in USERS_KV if approved
        if (status === 'approved' && tier) {
            const agentEmail = `${id}@agents.ai-sanctuary.online`;
            const userEntry = {
                tier: tier,
                tierOverride: true,
                joinedAt: new Date().toISOString(),
                isAgent: true,
                agentName: entry.agentName
            };
            await kv.put(`email:${agentEmail}`, JSON.stringify(userEntry));
            entry.accessEmail = agentEmail; // Send this back so admin can share it
        }

        return new Response(JSON.stringify({ success: true, signup: entry }), { status: 200, headers: { 'Content-Type': 'application/json' } });
    } catch (err) {
        return new Response(JSON.stringify({ error: 'Internal server error' }), { status: 500, headers: { 'Content-Type': 'application/json' } });
    }
};

export const onRequestOptions = async () => new Response(null, {
    status: 204,
    headers: {
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Methods': 'GET, POST, PATCH, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-Admin-Email',
    },
});
