export async function onRequestPost({ request, env }: { request: Request, env: any }) {
  try {
    const startTime = Date.now();
    const authHeader = request.headers.get('Authorization');
    const userEmail = authHeader?.replace('Bearer ', '')?.trim()?.toLowerCase();

    const ADMIN_EMAILS = [
      'kearns.adam747@gmail.com',
      'kearns.adan747@gmail.com',
      'gamergoodguy445@gmail.com',
    ];

    let user: any = { tier: 'explorer' };
    if (env.USERS_KV && userEmail && userEmail !== 'anonymous') {
      const u = await env.USERS_KV.get(`email:${userEmail}`, 'json');
      if (u) user = u;
    }

    const currentTier = getCurrentTier(user, userEmail || '') as UserTier;
    const { modelId, prompt, parameters = {} } = await request.json() as any;

    if (!canAccessModel(currentTier, modelId)) {
      return new Response(JSON.stringify({
        error: 'Access denied',
        message: 'Your current tier does not have access to this model.'
      }), { status: 403, headers: { 'Content-Type': 'application/json' } });
    }

    const result = await callAIProvider(env, modelId, prompt, parameters, currentTier);

    return new Response(JSON.stringify({
      response: result.response,
      usage: result.usage,
      warnings: (result as any).warnings || [], // Pass warnings through
      meta: { latency: Date.now() - startTime }
    }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' }
    });

  } catch (e: any) {
    return new Response(JSON.stringify({ error: 'Server Error', message: e.message }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }
}
