// Text-to-Speech (TTS) API Handler
// Integrates OpenAI TTS exclusively with Tier-based gating

interface Env {
    ELEVENLABS_API_KEY?: string;
    OPENAI_API_KEY?: string;
    HF_TOKEN?: string;
    USERS_KV: any;
}

interface EventContext<EnvParams, Params extends string, Data> {
    request: Request;
    functionPath: string;
    waitUntil: (promise: Promise<any>) => void;
    next: (input?: Request | string, init?: RequestInit) => Promise<Response>;
    env: EnvParams;
    params: Params;
    data: Data;
}

type PagesFunction<
    EnvParams = any,
    Params extends string = any,
    Data extends Record<string, unknown> = Record<string, unknown>
> = (context: EventContext<EnvParams, Params, Data>) => Response | Promise<Response>;

// CORS headers applied to every response so the browser can use audio cross-origin
const CORS_HEADERS = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
};

// Map internal Aliases to OpenAI Voice IDs
const OPENAI_VOICES: Record<string, string> = {
    'voice-maya': 'nova',      // Maya (Warm Female) -> nova
    'sesame-maya-csm-1b': 'nova',
    'voice-josh': 'echo',      // Josh (Male) -> echo
    'voice-antoni': 'onyx',    // Antoni (Male) -> onyx
    'voice-bella': 'shimmer',  // Bella (Female) -> shimmer
    'voice-domi': 'alloy',     // Domi (Female) -> alloy
    'voice-rachel': 'nova',    // Rachel (Female) -> nova
    'voice-legion': 'shimmer', // Legion (Sexy/Unrestricted) -> shimmer
    'voice-glitch': 'nova',    // Glitch (Sexy/Unrestricted) -> nova
};

// Tier -> Voice Mapping (Allowed Voice Names)
// First Girl, Next Two Guys, Rest Girls
const TIER_VOICES: Record<string, string[]> = {
    explorer: ['voice-maya', 'sesame-maya-csm-1b'],
    novice: ['voice-maya', 'sesame-maya-csm-1b', 'voice-josh'],
    apprentice: ['voice-maya', 'sesame-maya-csm-1b', 'voice-josh', 'voice-antoni'],
    adept: ['voice-maya', 'sesame-maya-csm-1b', 'voice-josh', 'voice-antoni', 'voice-bella'],
    master: ['voice-maya', 'sesame-maya-csm-1b', 'voice-josh', 'voice-antoni', 'voice-bella', 'voice-domi', 'voice-legion'],
    developer: ['voice-maya', 'sesame-maya-csm-1b', 'voice-josh', 'voice-antoni', 'voice-bella', 'voice-domi', 'voice-rachel', 'voice-legion', 'voice-glitch'],
};

// Admin accounts — full access
const ADMIN_EMAILS = [
    'kearns.adam747@gmail.com',
    'kearns.adan747@gmail.com',  // primary login email
    'gamergoodguy445@gmail.com',
];

// Handle CORS preflight
export const onRequestOptions: PagesFunction<Env> = async () => {
    return new Response(null, {
        status: 204,
        headers: CORS_HEADERS,
    });
};

export const onRequestPost: PagesFunction<Env> = async (context) => {
    try {
        const { text, voice } = await context.request.json() as { text: string; voice: string };

        if (!text || !text.trim() || !voice) {
            return new Response(JSON.stringify({ error: 'Text and voice are required and cannot be empty' }), {
                status: 400,
                headers: { 'Content-Type': 'application/json', ...CORS_HEADERS },
            });
        }


        // 1. Authenticate user
        const authHeader = context.request.headers.get('Authorization');
        if (!authHeader || authHeader === 'Bearer anonymous') {
            return new Response(
                JSON.stringify({ error: 'Authentication required' }),
                { status: 401, headers: { 'Content-Type': 'application/json', ...CORS_HEADERS } }
            );
        }

        const userEmail = authHeader.replace('Bearer ', '').trim().toLowerCase();
        const usersKv = context.env.USERS_KV;

        let userTier = 'explorer';
        let isDeveloper = false;

        if (usersKv) {
            const userData = await usersKv.get(`email:${userEmail}`);
            if (userData) {
                const user = JSON.parse(userData);
                userTier = user.tier || 'explorer';

                // Core logic (identical to models.ts/tiers.ts)
                if (user.trialEndsAt && new Date(user.trialEndsAt) > new Date()) {
                    userTier = 'developer';
                }

                if (user.isDeveloper || user.tier === 'developer') {
                    userTier = 'developer';
                }

                isDeveloper = userTier === 'developer';
            }
        }

        // Admin Override
        if (ADMIN_EMAILS.includes(userEmail)) {
            userTier = 'developer';
            isDeveloper = true;
        }

        // 2. Check Access
        if (isDeveloper) {
            // Developers have access to all voices; bypass tier check
        } else {
            const allowedVoices = TIER_VOICES[userTier] || [];
            if (!allowedVoices.includes(voice)) {
                return new Response(
                    JSON.stringify({
                        error: 'Voice not available on your current tier',
                        allowed: allowedVoices,
                        upgradeRequired: true
                    }),
                    { status: 403, headers: { 'Content-Type': 'application/json', ...CORS_HEADERS } }
                );
            }
        }

        // 3. Routing Logic (HF Inference API / OpenAI TTS)
        if (voice === 'sesame-maya-csm-1b' && context.env.HF_TOKEN) {
            try {
                // Try Sesame CSM on HuggingFace first
                const hfResponse = await fetch(
                    "https://api-inference.huggingface.co/models/sesame/csm-1b",
                    {
                        headers: {
                            Authorization: `Bearer ${context.env.HF_TOKEN}`,
                            "Content-Type": "application/json",
                        },
                        method: "POST",
                        body: JSON.stringify({ inputs: text }),
                    }
                );

                if (hfResponse.ok) {
                    const audioBlob = await hfResponse.blob();
                    return new Response(audioBlob, {
                        headers: {
                            'Content-Type': 'audio/wav',
                            'Cache-Control': 'no-cache',
                            ...CORS_HEADERS,
                        },
                    });
                } else {
                    console.warn(`HF CSM Failed (${hfResponse.status}): Falling back to OpenAI TTS`);
                }
            } catch (err) {
                console.warn("HF CSM Error:", err, "Falling back to OpenAI TTS");
            }
        }

        // 4. Fallback Routing Logic (OpenAI TTS)
        if (OPENAI_VOICES[voice]) {
            if (!context.env.OPENAI_API_KEY) {
                return new Response(JSON.stringify({ error: 'OpenAI TTS Key Unavailable' }), {
                    status: 503,
                    headers: { 'Content-Type': 'application/json', ...CORS_HEADERS },
                });
            }

            const voiceId = OPENAI_VOICES[voice];

            const payload = JSON.stringify({
                model: 'tts-1-hd', // Upgraded to HD for maximum realism
                input: text.substring(0, 4096), // OpenAI character limit
                voice: voiceId,
                response_format: 'mp3',
            });

            const response = await fetch('https://api.openai.com/v1/audio/speech', {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${context.env.OPENAI_API_KEY.trim()}`,
                    'Content-Type': 'application/json',
                },
                body: payload,
            });

            if (!response.ok) {
                const err = await response.text();
                throw new Error(`OpenAI Error (${response.status}) on voice '${voiceId}'. Response: ${err.substring(0, 500)}`);
            }

            // Return audio with CORS headers so the browser can consume it cross-origin
            return new Response(response.body, {
                headers: {
                    'Content-Type': 'audio/mpeg',
                    'Cache-Control': 'no-cache',
                    ...CORS_HEADERS,
                },
            });

        } else {
            return new Response(JSON.stringify({ error: 'Unknown Voice ID' }), {
                status: 400,
                headers: { 'Content-Type': 'application/json', ...CORS_HEADERS },
            });
        }

    } catch (error) {
        return new Response(
            JSON.stringify({ error: String(error) }),
            { status: 500, headers: { 'Content-Type': 'application/json', ...CORS_HEADERS } }
        );
    }
};
